      "rewritten_requirement": "The system shall allow small and medium scale sellers to list their products."
    },
    {
      "source_requirement": "Sellers can showcase their products in the application.",
      "rewritten_requirement": "The system shall enable sellers to showcase their products."
    },
    {
      "source_requirement": "Sellers can advertise their products in the application.",
      "rewritten_requirement": "The system shall allow sellers to advertise their products."
    },
    {
      "source_requirement": "Customers can view all the products available from various sellers in the application.",
      "rewritten_requirement": "The system shall display a list of all products available from various sellers for customers to view."
    },
    {
      "source_requirement": "Customers can purchase products online through the application.",
      "rewritten_requirement": "The system shall enable customers to purchase products online."
    },
    {
      "source_requirement": "Customers can rate or give a review for the product in the application.",
      "rewritten_requirement": "The system shall allow customers to rate or give reviews for products."
    },
    {
      "source_requirement": "Customers can report a seller for any violations in delivery or if the product does not meet the specified requirement in the application.",
      "rewritten_requirement": "The system shall enable customers to report sellers for any violations in delivery or non-compliance with product specifications."
    },
    {
      "source_requirement": "Customers can view the contact information and rating of the seller before buying the product in the application.",
      "rewritten_requirement": "The system shall display the contact information and rating of sellers to customers before purchase."
